# --- Helper function to get request body hash ---
def get_request_body_hash(request_data):
    """
    Generates a SHA256 hash of the request body.
    Returns 'no_body' if no data is present.
    """
    if request_data:
        return hashlib.sha256(request_data).hexdigest()
    return 'no_body'

# --- Middleware for metrics collection ---
@app.before_request
def before_request_hook():
    """
    Records the start time of the request and extracts user/API key from headers.
    Also stores the raw request body for hashing later.
    """
    g.start_time = time.time()
    g.user_id = request.headers.get('X-User-Id', 'anonymous')
    g.api_key = request.headers.get('X-Api-Key', 'unknown')
    
